    46→/// Run harness CLI command in a project directory
    47→#[tauri::command]
    48→fn run_harness_command(project_path: String, args: Vec<String>) -> Result<String, String> {
    49→    use std::process::Command;
    50→
    51→    // Get the harness binary path (same directory as this executable)
    52→    let current_exe = std::env::current_exe().map_err(|e| e.to_string())?;
    53→    let harness_path = current_exe.parent()
    54→        .ok_or("Cannot find parent directory")?
    55→        .join("harness");
    56→
    57→    // Run harness command
    58→    let output = Command::new(&harness_path)
