    60→        .args(&args)
    61→        .output()
    62→        .map_err(|e| format!("Failed to run harness: {}", e))?;
    63→
    64→    if output.status.success() {
    65→        Ok(String::from_utf8_lossy(&output.stdout).to_string())
    66→    } else {
    67→        let stderr = String::from_utf8_lossy(&output.stderr);
