    74→fn get_git_info(project_path: String) -> Result<String, String> {
    75→    use std::process::Command;
    76→
    77→    // Run git log to get the last commit
    78→    let output = Command::new("git")
    79→        .current_dir(&project_path)
    80→        .args(["log", "-1", "--format=%H|%s|%an|%aI"])
    81→        .output()
    82→        .map_err(|e| format!("Failed to run git: {}", e))?;
