     1→//! File watcher module for .harness directory changes (F008)
     2→//!
     3→//! Watches the .harness directory (specifically harness.db) for changes
     4→//! and emits Tauri events to notify the frontend.
     5→
     6→use notify_debouncer_mini::{new_debouncer, DebouncedEventKind};
     7→use parking_lot::Mutex;
     8→use std::collections::HashMap;
     9→use std::path::PathBuf;
    10→use std::sync::Arc;
    11→use std::time::Duration;
    12→use tauri::{AppHandle, Emitter};
    13→
    14→/// Event payload for harness file changes
    15→#[derive(Clone, serde::Serialize)]
    16→pub struct HarnessChangeEvent {
    17→    /// The project path being watched
    18→    pub project_path: String,
    19→    /// Type of change: "db", "config", or "unknown"
    20→    pub change_type: String,
    21→    /// The file that changed (relative to .harness/)
    22→    pub file: String,
    23→}
    24→
    25→/// Manages file watchers for multiple projects
    26→pub struct WatcherManager {
    27→    /// Map of project_path -> watcher handle (stored as thread join handle)
    28→    watchers: Mutex<HashMap<String, std::thread::JoinHandle<()>>>,
    29→    /// Shutdown signals for each watcher
    30→    shutdown_signals: Mutex<HashMap<String, Arc<Mutex<bool>>>>,
    31→}
    32→
    33→impl WatcherManager {
    34→    pub fn new() -> Self {
    35→        Self {
    36→            watchers: Mutex::new(HashMap::new()),
    37→            shutdown_signals: Mutex::new(HashMap::new()),
    38→        }
    39→    }
    40→
    41→    /// Start watching a project's .harness directory
    42→    pub fn start_watching(&self, app: AppHandle, project_path: String) -> Result<(), String> {
    43→        let harness_dir = PathBuf::from(&project_path).join(".harness");
    44→
    45→        if !harness_dir.exists() {
    46→            return Err(format!(
    47→                "No .harness directory found at: {}",
    48→                harness_dir.display()
    49→            ));
    50→        }
    51→
    52→        // Check if already watching
    53→        {
    54→            let watchers = self.watchers.lock();
    55→            if watchers.contains_key(&project_path) {
    56→                return Ok(()); // Already watching, no-op
    57→            }
    58→        }
    59→
    60→        // Create shutdown signal
    61→        let shutdown_signal = Arc::new(Mutex::new(false));
    62→        let shutdown_signal_clone = shutdown_signal.clone();
    63→
    64→        let project_path_clone = project_path.clone();
    65→        let harness_dir_clone = harness_dir.clone();
    66→
    67→        // Spawn watcher thread
    68→        let handle = std::thread::spawn(move || {
    69→            // Create debouncer with 500ms delay
    70→            let (tx, rx) = std::sync::mpsc::channel();
    71→
    72→            let mut debouncer = match new_debouncer(Duration::from_millis(500), tx) {
    73→                Ok(d) => d,
    74→                Err(e) => {
    75→                    eprintln!("Failed to create debouncer: {}", e);
    76→                    return;
    77→                }
    78→            };
    79→
    80→            // Watch the .harness directory
    81→            if let Err(e) = debouncer
    82→                .watcher()
    83→                .watch(&harness_dir_clone, notify::RecursiveMode::NonRecursive)
    84→            {
    85→                eprintln!("Failed to watch directory: {}", e);
    86→                return;
    87→            }
    88→
    89→            println!(
    90→                "🔍 Watching .harness directory: {}",
    91→                harness_dir_clone.display()
    92→            );
    93→
    94→            // Event loop
    95→            loop {
    96→                // Check for shutdown signal
    97→                if *shutdown_signal_clone.lock() {
    98→                    println!("🛑 Stopping watcher for: {}", project_path_clone);
    99→                    break;
   100→                }
   101→
   102→                // Check for file changes with timeout
   103→                match rx.recv_timeout(Duration::from_millis(100)) {
   104→                    Ok(Ok(events)) => {
   105→                        for event in events {
   106→                            if event.kind == DebouncedEventKind::Any {
   107→                                let file_name = event
   108→                                    .path
   109→                                    .file_name()
   110→                                    .and_then(|n| n.to_str())
   111→                                    .unwrap_or("unknown")
   112→                                    .to_string();
   113→
   114→                                let change_type = if file_name.ends_with(".db")
   115→                                    || file_name.ends_with(".db-wal")
   116→                                    || file_name.ends_with(".db-shm")
   117→                                {
   118→                                    "db"
   119→                                } else if file_name.ends_with(".json") {
   120→                                    "config"
   121→                                } else {
   122→                                    "unknown"
   123→                                };
   124→
   125→                                let payload = HarnessChangeEvent {
   126→                                    project_path: project_path_clone.clone(),
   127→                                    change_type: change_type.to_string(),
   128→                                    file: file_name,
   129→                                };
   130→
   131→                                // Emit event to frontend
   132→                                if let Err(e) = app.emit("harness-change", payload) {
   133→                                    eprintln!("Failed to emit harness-change event: {}", e);
   134→                                }
   135→                            }
   136→                        }
   137→                    }
   138→                    Ok(Err(e)) => {
   139→                        eprintln!("Watch error: {:?}", e);
   140→                    }
   141→                    Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {
   142→                        // No events, continue polling
   143→                    }
   144→                    Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
   145→                        println!("Watcher channel disconnected");
   146→                        break;
   147→                    }
   148→                }
   149→            }
   150→        });
   151→
   152→        // Store handle and shutdown signal
   153→        {
   154→            let mut watchers = self.watchers.lock();
   155→            watchers.insert(project_path.clone(), handle);
   156→        }
   157→        {
   158→            let mut signals = self.shutdown_signals.lock();
   159→            signals.insert(project_path, shutdown_signal);
   160→        }
   161→
   162→        Ok(())
   163→    }
   164→
   165→    /// Stop watching a project
   166→    pub fn stop_watching(&self, project_path: &str) -> Result<(), String> {
   167→        // Signal shutdown
   168→        {
   169→            let signals = self.shutdown_signals.lock();
   170→            if let Some(signal) = signals.get(project_path) {
   171→                *signal.lock() = true;
   172→            }
   173→        }
   174→
   175→        // Wait for thread to finish and remove
   176→        let handle = {
   177→            let mut watchers = self.watchers.lock();
   178→            watchers.remove(project_path)
   179→        };
   180→
   181→        if let Some(handle) = handle {
   182→            let _ = handle.join();
   183→        }
   184→
   185→        // Clean up signal
   186→        {
   187→            let mut signals = self.shutdown_signals.lock();
   188→            signals.remove(project_path);
   189→        }
   190→
   191→        Ok(())
   192→    }
   193→
   194→    /// Get list of watched projects
   195→    pub fn list_watching(&self) -> Vec<String> {
   196→        let watchers = self.watchers.lock();
   197→        watchers.keys().cloned().collect()
   198→    }
   199→}
   200→
   201→impl Default for WatcherManager {
   202→    fn default() -> Self {
   203→        Self::new()
   204→    }
   205→}
   206→
   207→// Tauri commands
