use rusqlite::{params, Connection, OptionalExtension};

use super::embeddings;
use super::types::{PaginatedResult, ProjectTask, TaskStatus};
use super::DbResult;

/// Default page size for list operations.
pub const DEFAULT_PAGE_SIZE: usize = 50;

// =============================================================================
// CREATE
