}

#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
enum TaskStatusArg {
    Backlog,
    Todo,
    Doing,
    Review,
    Qa,
    Done,
}

impl From<TaskStatusArg> for db::TaskStatus {
    fn from(arg: TaskStatusArg) -> Self {
        match arg {
            TaskStatusArg::Backlog => db::TaskStatus::Backlog,
            TaskStatusArg::Todo => db::TaskStatus::Todo,
            TaskStatusArg::Doing => db::TaskStatus::Doing,
            TaskStatusArg::Review => db::TaskStatus::Review,
            TaskStatusArg::Qa => db::TaskStatus::Qa,
            TaskStatusArg::Done => db::TaskStatus::Done,
        }
    }
}

